'use client'

import { useState } from 'react'

export default function JSONFormatter() {
  const [input, setInput] = useState('')
  const [output, setOutput] = useState('')
  const [error, setError] = useState<string | null>(null)

  function formatJSON() {
    try {
      const obj = JSON.parse(input)
      setOutput(JSON.stringify(obj, null, 2))
      setError(null)
    } catch (e: any) {
      setError(e.message)
      setOutput('')
    }
  }

  function reset() {
    setInput('')
    setOutput('')
    setError(null)
  }

  return (
    <main className="container mx-auto p-4">
      <h1 className="text-2xl font-bold">JSON Formatter</h1>
      <div className="mt-4 max-w-2xl">
        <textarea className="w-full h-48 p-2 border rounded" value={input} onChange={e => setInput(e.target.value)} placeholder="Paste JSON here" />

        <div className="flex gap-2 mt-3">
          <button onClick={formatJSON} className="px-4 py-2 bg-blue-600 text-white rounded">Format</button>
          <button onClick={reset} className="px-4 py-2 border rounded">Reset</button>
        </div>

        {error && <div className="mt-3 text-red-600">Error: {error}</div>}

        {output && (
          <pre className="mt-3 p-3 bg-slate-50 dark:bg-slate-800 rounded overflow-auto">{output}</pre>
        )}
      </div>
    </main>
  )
}
